const app = express();
app.use(bodyParser.urlencoded({ extended: true }));

const authorizationCodes = new Map();
const clients = new Map(); // Store client_id and redirect_uri
const tokens = new Map(); // Store access tokens

// Dummy user consent
const userConsent = true;

